/*\n  # Create inspection bookings table\n\n  1. New Tables\n    - `inspection_bookings`\n      - `id` (uuid, primary key)\n      - `full_name` (text) - Customer full name\n      - `phone` (text) - Contact phone number\n      - `email` (text) - Contact email address\n      - `address` (text) - Property address\n      - `city` (text) - Property city\n      - `zip_code` (text) - Property ZIP code\n      - `preferred_date` (date) - Preferred inspection date\n      - `preferred_time` (text) - Preferred time window\n      - `inspection_type` (text) - Type of inspection requested\n      - `storm_score` (integer) - Storm risk score from report\n      - `risk_level` (text) - Risk level category\n      - `status` (text) - Booking status (pending, confirmed, completed, cancelled)\n      - `created_at` (timestamptz) - Record creation timestamp\n      - `updated_at` (timestamptz) - Record update timestamp\n\n  2. Security\n    - Enable RLS on `inspection_bookings` table\n    - Add policy for inserting bookings (public access for form submissions)\n    - Add policy for authenticated users to view their own bookings\n*/\n\nCREATE TABLE IF NOT EXISTS inspection_bookings (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  full_name text NOT NULL,\n  phone text NOT NULL,\n  email text NOT NULL,\n  address text NOT NULL,\n  city text NOT NULL,\n  zip_code text NOT NULL,\n  preferred_date date NOT NULL,\n  preferred_time text NOT NULL,\n  inspection_type text NOT NULL,\n  storm_score integer,\n  risk_level text,\n  status text DEFAULT 'pending',\n  created_at timestamptz DEFAULT now(),\n  updated_at timestamptz DEFAULT now()\n);
\n\nALTER TABLE inspection_bookings ENABLE ROW LEVEL SECURITY;
\n\nCREATE POLICY "Anyone can insert inspection bookings"\n  ON inspection_bookings\n  FOR INSERT\n  TO anon\n  WITH CHECK (true);
\n\nCREATE POLICY "Users can view their own bookings by email"\n  ON inspection_bookings\n  FOR SELECT\n  TO anon\n  USING (true);
\n;
